#[cfg(test)]
#[test]
fn test_verify_issuance_valid() {
    use crate::options::{OptionsArguments, get_options_address};
    use crate::sdk::finance::issuance_validation::validate::verify_issuance;
    use crate::sdk::taproot_pubkey_gen::TaprootPubkeyGen;
    use simplicityhl::elements::Transaction;
    use simplicityhl::elements::pset::serialize::Deserialize;
    use simplicityhl_core::{Encodable, SimplicityNetwork};

    let option_arguments_str = "";
    let option_arguments: OptionsArguments =
        OptionsArguments::decode(&hex::decode(option_arguments_str).expect("Invalid hex")).unwrap();

    let taproot_str = "513bcc097c6a379a0c1ada4c896cae70df6b8b59734347e642598db966532d2b:02c6edd467c5aca948c6e43486c99393afa0b51802dad8c300a1b152b8fdda7969:tex1plhc0pau4pasn7lwnemz448ccf0rmhg3v9tkfmsssn83057te7grqwkp0xd";
    let taproot_gen = TaprootPubkeyGen::build_from_str(
        taproot_str,
        &option_arguments,
        SimplicityNetwork::LiquidTestnet,
        &get_options_address,
    )
    .unwrap();

    let tx_hex = "";
    let tx_bytes = hex::decode(tx_hex.trim()).unwrap();
    let tx: Transaction = Deserialize::deserialize(&tx_bytes[..]).unwrap();

    let _ = verify_issuance(&tx, &option_arguments, &taproot_gen.address.script_pubkey());
}

#[test]
fn test_verify_issuance_corrupt() {
    use crate::options::{OptionsArguments, get_options_address};
    use crate::sdk::finance::issuance_validation::validate::verify_issuance;
    use crate::sdk::taproot_pubkey_gen::TaprootPubkeyGen;
    use simplicityhl::elements::pset::serialize::Deserialize;
    use simplicityhl::elements::{Script, Transaction};
    use simplicityhl_core::{Encodable, SimplicityNetwork};
    use std::str::FromStr;
    let option_arguments_str = "";
    let option_arguments: OptionsArguments =
        OptionsArguments::decode(&hex::decode(option_arguments_str).expect("Invalid hex")).unwrap();

    let taproot_str = "513bcc097c6a379a0c1ada4c896cae70df6b8b59734347e642598db966532d2b:02c6edd467c5aca948c6e43486c99393afa0b51802dad8c300a1b152b8fdda7969:tex1plhc0pau4pasn7lwnemz448ccf0rmhg3v9tkfmsssn83057te7grqwkp0xd";
    let taproot_gen = TaprootPubkeyGen::build_from_str(
        taproot_str,
        &option_arguments,
        SimplicityNetwork::LiquidTestnet,
        &get_options_address,
    )
    .unwrap();

    let tx_hex = "";
    let tx_bytes = hex::decode(tx_hex.trim()).unwrap();
    let mut tx: Transaction = Deserialize::deserialize(&tx_bytes[..]).unwrap();

    let reissuance_index = tx
        .output
        .iter()
        .position(|o| o.script_pubkey == taproot_gen.address.script_pubkey())
        .unwrap();

    // Corrupt Transaction
    let hacker_script = Script::from_str("00000000").unwrap();
    tx.output[reissuance_index].script_pubkey = hacker_script;

    let result = verify_issuance(&tx, &option_arguments, &taproot_gen.address.script_pubkey());

    match result {
        Ok(()) => panic!(
            "Test Failed: The verifier accepted a transaction with a stolen reissuance token!"
        ),
        Err(e) => {
            println!("Test Passed: Correctly caught error: {e:?}");
        }
    }
}
